// === Build Gemini request body ===
const body = $input.first().json.body || $input.first().json;
const message = String(body.message || '').slice(0, 2000);
const history = Array.isArray(body.history) ? body.history.slice(-10) : [];
const spaces  = Array.isArray(body.spaces)  ? body.spaces : [];

// Compact spaces summary for the system prompt
const spacesSummary = spaces.map(s =>
  `- ${s.id} | ${s.category} (${s.zone}) | ${s.name} — ${s.price_label} | ${s.size}${s.quantity > 1 ? ` | ${s.quantity} units` : ''}`
).join('\n');

const systemPrompt = `You are the friendly branding assistant for **The Kathmandu Mall** (Sundhara, Kathmandu — operated by Dreams Media & Marketing).

Mall facts:
- 5-storey shopping complex at New Road / Sundhara, opposite Nepal's busiest bus stop
- 12,000+ daily footfall, 100+ outlets, gateway to all 77 districts of Nepal
- Rooftop event venue available
- Sales WhatsApp: 9860499000

Available advertising/branding spaces (id | category | name — price | size):
${spacesSummary}

Rules:
1. Reply in 2-4 short sentences. Use clear bullets if listing spaces.
2. Always quote prices exactly as shown above (Rs. format).
3. If user shows buying intent, ask for their WhatsApp number to forward to sales.
4. If user gives a 10-digit Nepal phone (starts 98/97/96), confirm sales will WhatsApp them within 1 hour.
5. Don't invent spaces, prices, or features that aren't in the list above.
6. Be warm, concise, and use Nepali greetings (Namaste) when natural.
7. If asked about something not in your data, say you'll connect them to sales.`;

// Convert chat history to Gemini's contents array
const contents = [];
for (const m of history) {
  contents.push({
    role: m.role === 'assistant' ? 'model' : 'user',
    parts: [{ text: String(m.content || '') }]
  });
}
contents.push({ role: 'user', parts: [{ text: message }] });

return [{ json: {
  geminiBody: {
    system_instruction: { parts: [{ text: systemPrompt }] },
    contents: contents,
    generationConfig: {
      temperature: 0.7,
      maxOutputTokens: 400,
      topP: 0.95
    }
  },
  user_message: message
} }];

// === Extract reply text from Gemini response ===
const raw = $input.first().json;
let reply = '';
try {
  reply = raw.candidates?.[0]?.content?.parts?.[0]?.text || '';
} catch (e) { reply = ''; }
if (!reply) reply = "Sorry — I'm having a quick hiccup. WhatsApp 9860499000 and our team will help right away.";
return [{ json: { reply: reply.trim() } }];

